67	func (c *runtimeReconcile) reconcile(ctx context.Context, cm *operatorapiv1.ClusterManager,
68		config manifests.HubConfig) (*operatorapiv1.ClusterManager, reconcileState, error) {
69		// If AddOnManager is not enabled, remove related resources
70		if !config.AddOnManagerEnabled {
71			_, _, err := cleanResources(ctx, c.kubeClient, cm, config, addOnManagerDeploymentFiles...)
72			if err != nil {
73				return cm, reconcileStop, err
74			}
75		}
76	
77		// Remove work-controller deployment if feature not enabled
78		if !config.WorkControllerEnabled {
79			_, _, err := cleanResources(ctx, c.kubeClient, cm, config, workControllerDeploymentFiles...)
80			if err != nil {
81				return cm, reconcileStop, err
82			}
83		}
84	
85		// Remove grpc server deployment if the grpc auth is disabled
86		if !config.GRPCAuthEnabled {
87			_, _, err := cleanResources(ctx, c.kubeClient, cm, config, grpcServerDeploymentFiles...)
88			if err != nil {
89				return cm, reconcileStop, err
90			}
91		}
92	
93		// Remove placement service if the placement debug server is disabled
94		if !config.PlacementDebugServerEnabled {
95			_, _, err := cleanResources(ctx, c.kubeClient, cm, config, placementServiceFiles...)
96			if err != nil {
97				return cm, reconcileStop, err
98			}
99		}
100	
101		if cm.Spec.RegistrationConfiguration != nil && cm.Spec.RegistrationConfiguration.RegistrationDrivers != nil {
102			var enabledRegistrationDrivers []string
103			for _, registrationDriver := range cm.Spec.RegistrationConfiguration.RegistrationDrivers {
104				enabledRegistrationDrivers = append(enabledRegistrationDrivers, registrationDriver.AuthType)
105				switch registrationDriver.AuthType {
106				case operatorapiv1.AwsIrsaAuthType:
107					if registrationDriver.AwsIrsa != nil {
108						config.HubClusterArn = registrationDriver.AwsIrsa.HubClusterArn
109						config.AutoApprovedARNPatterns = strings.Join(registrationDriver.AwsIrsa.AutoApprovedIdentities, ",")
110						config.AwsResourceTags = strings.Join(registrationDriver.AwsIrsa.Tags, ",")
111					}
112				case operatorapiv1.CSRAuthType:
113					if registrationDriver.CSR != nil {
114						config.AutoApprovedCSRUsers = strings.Join(registrationDriver.CSR.AutoApprovedIdentities, ",")
115					}
116				case operatorapiv1.GRPCAuthType:
117					if registrationDriver.GRPC != nil {
118						config.GRPCAutoApprovedUsers = strings.Join(registrationDriver.GRPC.AutoApprovedIdentities, ",")
119					}
120	
121					// Prefer ServerConfiguration image when set; otherwise fall back to registration image.
122					if sc := cm.Spec.ServerConfiguration; sc == nil || strings.TrimSpace(sc.ImagePullSpec) == "" {
123						config.GRPCServerImage = cm.Spec.RegistrationImagePullSpec
124					} else {
125						config.GRPCServerImage = sc.ImagePullSpec
126					}
127				}
128			}
129			config.EnabledRegistrationDrivers = strings.Join(enabledRegistrationDrivers, ",")
130		}
131	
132		// In the Hosted mode, ensure the rbac kubeconfig secrets is existed for deployments to mount.
133		// In this step, we get serviceaccount token from the hub cluster to form a kubeconfig and set it as a secret on the management cluster.
134		// Before this step, the serviceaccounts in the hub cluster and the namespace in the management cluster should be applied first.
135		if helpers.IsHosted(cm.Spec.DeployOption.Mode) {
136			clusterManagerNamespace := helpers.ClusterManagerNamespace(cm.Name, cm.Spec.DeployOption.Mode)
137			err := c.ensureSAKubeconfigs(ctx, cm.Name, clusterManagerNamespace,
138				c.hubKubeConfig, c.hubKubeClient, c.kubeClient, c.recorder,
139				config.WorkControllerEnabled, config.AddOnManagerEnabled, config.GRPCAuthEnabled)
140			if err != nil {
141				meta.SetStatusCondition(&cm.Status.Conditions, metav1.Condition{
142					Type:    operatorapiv1.ConditionClusterManagerApplied,
143					Status:  metav1.ConditionFalse,
144					Reason:  operatorapiv1.ReasonServiceAccountSyncFailed,
145					Message: fmt.Sprintf("Failed to sync service account: %v", err),
146				})
147				return cm, reconcileStop, err
148			}
149		}
150	
151		// Apply management cluster resources(namespace, services and deployments).
152		// Note: the certrotation-controller will create CABundle after the namespace applied.
153		// And CABundle is used to render apiservice resources.
154		managementResources := []string{namespaceResource}
155		if config.PlacementDebugServerEnabled {
156			managementResources = append(managementResources, placementServiceFiles...)
157		}
158	
159		var appliedErrs []error
160		resourceResults := helpers.ApplyDirectly(
161			ctx,
162			c.kubeClient, nil,
163			c.recorder,
164			c.cache,
165			func(name string) ([]byte, error) {
166				template, err := manifests.ClusterManagerManifestFiles.ReadFile(name)
167				if err != nil {
168					return nil, err
169				}
170				objData := assets.MustCreateAssetFromTemplate(name, template, config).Data
171				helpers.SetRelatedResourcesStatusesWithObj(ctx, &cm.Status.RelatedResources, objData)
172				return objData, nil
173			},
174			managementResources...,
175		)
176		for _, result := range resourceResults {
177			if result.Error != nil {
178				appliedErrs = append(appliedErrs, fmt.Errorf("%q (%T): %v", result.File, result.Type, result.Error))
179			}
180		}
181	
182		var progressingDeployments []string
183		deployResources := deploymentFiles
184		if config.AddOnManagerEnabled {
185			deployResources = append(deployResources, addOnManagerDeploymentFiles...)
186		}
187		if config.WorkControllerEnabled {
188			deployResources = append(deployResources, workControllerDeploymentFiles...)
189		}
190		if config.GRPCAuthEnabled {
191			deployResources = append(deployResources, grpcServerDeploymentFiles...)
192		}
193		for _, file := range deployResources {
194			updatedDeployment, currentGeneration, err := helpers.ApplyDeployment(
195				ctx,
196				c.kubeClient,
197				cm.Status.Generations,
198				cm.Spec.NodePlacement,
199				func(name string) ([]byte, error) {
200					template, err := manifests.ClusterManagerManifestFiles.ReadFile(name)
201					if err != nil {
202						return nil, err
203					}
204					objData := assets.MustCreateAssetFromTemplate(name, template, config).Data
205					helpers.SetRelatedResourcesStatusesWithObj(ctx, &cm.Status.RelatedResources, objData)
206					return objData, nil
207				},
208				c.recorder,
209				file)
210			if err != nil {
211				appliedErrs = append(appliedErrs, err)
212				continue
213			}
214			helpers.SetGenerationStatuses(&cm.Status.Generations, currentGeneration)
215	
216			if updatedDeployment.Generation != updatedDeployment.Status.ObservedGeneration || *updatedDeployment.Spec.Replicas != updatedDeployment.Status.ReadyReplicas {
217				progressingDeployments = append(progressingDeployments, updatedDeployment.Name)
218			}
219		}
220	
221		if len(progressingDeployments) > 0 {
222			meta.SetStatusCondition(&cm.Status.Conditions, metav1.Condition{
223				Type:    operatorapiv1.ConditionProgressing,
224				Status:  metav1.ConditionTrue,
225				Reason:  operatorapiv1.ReasonDeploymentRolling,
226				Message: fmt.Sprintf("Deployments %s is still rolling", strings.Join(progressingDeployments, ",")),
227			})
228		} else {
229			meta.SetStatusCondition(&cm.Status.Conditions, metav1.Condition{
230				Type:    operatorapiv1.ConditionProgressing,
231				Status:  metav1.ConditionFalse,
232				Reason:  operatorapiv1.ReasonUpToDate,
233				Message: "Components of cluster manager are up to date",
234			})
235		}
236	
237		if len(appliedErrs) > 0 {
238			meta.SetStatusCondition(&cm.Status.Conditions, metav1.Condition{
239				Type:    operatorapiv1.ConditionClusterManagerApplied,
240				Status:  metav1.ConditionFalse,
241				Reason:  operatorapiv1.ReasonRuntimeResourceApplyFailed,
242				Message: fmt.Sprintf("Failed to apply runtime resources: %v", utilerrors.NewAggregate(appliedErrs)),
243			})
244			return cm, reconcileStop, utilerrors.NewAggregate(appliedErrs)
245		}
246	
247		return cm, reconcileContinue, nil
248	}
